INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ra, uma companhia mista ou uma companhia financeira mista, estas e as respetivas filiais, incluindo as filiais que não estão incluídas no âmbito da supervisão em base consolidada, são obrigadas a apresentar ao Banco de Portugal todas as informações e esclarecimentos úteis para a supervisão.
