INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('e se referem os n.os 1, 4 e 5 são atualizadas anualmente ou, em circunstâncias excecionais, sempre que a autoridade competente responsável pela supervisão das filiais de uma instituição de crédito-mãe da União Europeia, de uma companhia financeira-mãe da União Europeia ou de uma companhia financeira mista-mãe da União Europeia apresente por escrito um pedido devidamente fundamentado à autoridade responsável pela supervisão numa base consolidada no sentido de atualizar a decisão sobre a aplicação das medidas corretivas previstas no n.º 3 do artigo 116.º-C ou a decisão sobre requisitos específicos de liquidez nos termos do artigo 116.º-M.
